const { PrismaClient } = require("@prisma/client");
const prisma = new PrismaClient();

async function main() {
  const refs = [
    "11188005235620260303115134255",
    "11188005235620260303115112071",
  ];

  const expenses = await prisma.expense.findMany({
    where: { reference: { in: refs } },
    select: {
      id: true,
      reference: true,
      amount: true,
      spentAt: true,
      createdAt: true,
      importBatchId: true,
      paymentMethod: true,
      description: true,
      expenseItemId: true,
    },
    orderBy: [{ createdAt: "desc" }],
  });

  const batches = await prisma.importBatch.findMany({
    where: { id: { in: expenses.map((x) => x.importBatchId).filter(Boolean) } },
    select: { id: true, fileName: true, uploadedAt: true, kind: true },
  });

  console.log(JSON.stringify({
    refs,
    expenseCount: expenses.length,
    expenses,
    batches,
  }, null, 2));
}

main().catch((e) => { console.error(e); process.exitCode = 1; }).finally(async () => { await prisma.$disconnect(); });
